<?php require_once __DIR__.'/../includes/business-header.php';require_learner();$courses=business_courses($pdo);$s=$pdo->prepare('SELECT b.*,lb.awarded_at FROM business_learner_badges lb JOIN business_badges b ON b.id=lb.badge_id WHERE lb.learner_id=? ORDER BY lb.awarded_at DESC');$s->execute([learner_id()]);$badges=$s->fetchAll();$s=$pdo->prepare('SELECT x.*,c.title course_title FROM business_certificates x JOIN business_courses c ON c.id=x.course_id WHERE x.learner_id=? ORDER BY x.issued_at DESC');$s->execute([learner_id()]);$certificates=$s->fetchAll();?>
<section class="business-dashboard"><div class="biz-container"><header><div><span class="biz-eyebrow">Learner command center</span><h1>Welcome back, <?=e($_SESSION['learner_name']??'business learner')?>.</h1><p>Continue building practical capability one focused lesson at a time.</p></div><div class="learner-score"><small>CREDENTIALS</small><strong><?=count($badges)+count($certificates)?></strong><span><?=count($badges)?> badges · <?=count($certificates)?> certificates</span></div></header><div class="dashboard-layout"><div><h2>Program progress</h2><div class="business-progress-list"><?php foreach($courses as $course):$p=business_progress($pdo,learner_id(),(int)$course['id']);?><a href="<?=business_url('course.php?slug='.urlencode($course['slug']))?>" style="--accent:<?=e($course['accent_color'])?>"><span><?=e($course['icon'])?></span><div><small><?=e($course['learner_type'])?></small><h3><?=e($course['title'])?></h3><div class="biz-progress"><i style="width:<?=$p['percent']?>%"></i></div><p><?=$p['done']?> / <?=$p['total']?> lessons · <?=$p['percent']?>%</p></div><b>↗</b></a><?php endforeach?></div></div><aside class="credential-panel"><h2>Credentials</h2><div class="badge-stack"><?php if(!$badges):?><p>Complete the Wanjiku case to earn your first business badge.</p><?php endif;foreach($badges as $badge):?><article><span><?=e($badge['icon'])?></span><div><b><?=e($badge['name'])?></b><small><?=e(date('M j, Y',strtotime($badge['awarded_at'])))?></small></div></article><?php endforeach?></div><?php if($certificates):?><h3>Certificates</h3><?php foreach($certificates as $cert):?><a class="certificate-link" href="<?=business_url('certificate.php?code='.urlencode($cert['certificate_code']))?>"><span>▣</span><div><b><?=e($cert['course_title'])?></b><small><?=e($cert['certificate_code'])?></small></div></a><?php endforeach;endif?></aside></div></div></section>
